        ...(filterData.nextActionToDate && { nextActionToDate: filterData.nextActionToDate.toISOString() }),
        ...(filterData.subStatuses && { subStatuses: filterData.subStatuses }),
        ...buildListFilterQueryParts(formData, cycleFilters),
