                              <button className="btn btn-sm btn-outline-primary" style={{
                                padding: "6px 12px",
                                fontSize: "11px",
                                fontWeight: "600",
                                display: "flex",
                                alignItems: "center",
                                gap: "4px"
                              }}
                                onClick={() => {
                                  openPanel(null, 'AddAllLeads');
                                }}
                              >
                                <i className="fas fa-plus" style={{ fontSize: "10px" }}></i>
                                Add Leads
                              </button>
